    self._timer = LxTimer:New()
    self:ModelFinish()

    self:StartCheckTimer()
end

function ModelRedPoint:InitData()
    self._redPointNetMap = {}       --后端数据
end

function ModelRedPoint:InitEventListenType()
    local parentTypesList = {}
    local childTypes = {}
    for k, v in pairs(self._parentTypes) do
        parentTypesList[k] = self:GetAllParentTypes(k)
        local list = childTypes[v]
        if not list then
            list = {}
            childTypes[v] = list
        end
        table.insert(list, k)
    end

    self._parentTypesList = parentTypesList

    self._childTypes = childTypes
    local childTypesList = {}
    for k, v in pairs(self._parentTypes) do
        childTypesList[v] = self:GetAllChildRedPoint(v)
    end

    self._childRedTypeList = childTypesList

    self._parentTypes = nil
    self._childTypes = nil
    printInfoN("InitEventListenType")


end

function ModelRedPoint:InitItemRelatives()
    local removeIds = {}
    for k, v in pairs(self._itemRelativeIds) do
        local childList = self._childRedTypeList[k]
        if childList then
            removeIds[k] = true
        end
    end

    for k, v in pairs(removeIds) do
        self._itemRelativeIds[k] = nil
    end
end

function ModelRedPoint:GetAllChildRedPoint(redPointType)
    local record = {}
    self:GetChildRedPoint(redPointType, record)
    local list = {}
    for k, v in pairs(record) do
        table.insert(list, k)
    end
    return list
end

function ModelRedPoint:GetChildRedPoint(redPointType, record)
    local childList = self._childTypes[redPointType]
    if not childList then
        return
    end

    for k, v in pairs(childList) do
        if not record[v] then
            record[v] = true
            self:GetChildRedPoint(v, record)
        end
    end
end

function ModelRedPoint:GetAllParentTypes(redPointType)
    local parentTypes = self._parentTypes
    local record = {}
    local list = {}
    local curType = redPointType
    while true do
        local parentType = parentTypes[curType]
        if not parentType then
            break
        end
        if record[parentType] then
            break
        end
        record[parentType] = true
        table.insert(list, parentType)
        curType = parentType
    end
    return list
end

function ModelRedPoint:RefreshRedPoint(redPointType)
    FireEvent(EventNames.ON_RED_POINT_CHANGE, redPointType)
end

function ModelRedPoint:GetRedPathConfig()
    return self._prefabNameConfig
end

