local redPointPath = "/redPoint"

function ModelRedPoint:ParseConfig()
    self._prefabNameConfig = {}
    self._parentTypes = {}

    self._funcIdToRedId = {}
    self._redIdToFuncId = {}

    self._itemRelativeIds = {}

    self._clickRelativeMap = {}

    ---不走原本红点设置的功能id
    self._noSetRepointFuncId = {
        12410000,
        12420000,
        12430000,
        12440000,
    }

    for k, v in pairs(GameTable.HintPointConfigRef) do
        local lastId = v.lastId
        if lastId > 0 then
            self._parentTypes[k] = lastId
        end

        local funcId = v.functionName

        if funcId > 0 then

            local old = self._funcIdToRedId[funcId]
            if old then
                printErrorN(string.format("功能id 不可重复 funcId %s  redRefId %s ", funcId, k))
            end
            self._funcIdToRedId[funcId] = k
            self._redIdToFuncId[k] = funcId

            local uiPath = gModelFunctionOpen:GetPath(funcId)
            local isNotSetRedpint = false
            for _, noSetPathValue in ipairs(self._noSetRepointFuncId) do
                if funcId == noSetPathValue then
                    isNotSetRedpint = true
                    break
                end
            end

            if uiPath and (not isNotSetRedpint) then
                local s, e = string.find(uiPath, "/")
                if s and e then
                    local prefabName = string.sub(uiPath, 1, s - 1)

                    if prefabName then
                        local list = self._prefabNameConfig[prefabName]
                        if not list then
                            list = {}
                            self._prefabNameConfig[prefabName] = list
                        end

                        local pointType = v.redPointType

                        if pointType > 0 then
                            local isOnEff = v.effectRedPoint == 1
                            local path = nil
                            if isOnEff then
                                path = uiPath
                            else
                                path = uiPath .. redPointPath

                                if prefabName == "MapCity" then
                                    local tempstr = string.split(uiPath, "/")
                                    prefabName = tempstr[#tempstr] == nil and prefabName or tempstr[#tempstr]
                                    path = prefabName .. "/CityEnterBubble/timeBg" .. redPointPath
                                end

                            end
                            local data = {
                                typeId = v.refId,
                                pointType = pointType,
                                path = path,
                                isOnEff = isOnEff,
                            }
                            table.insert(list, data)
                        end
                    end
                end
            end
        end

        if v.disappearType == 4 then
            self._itemRelativeIds[v.refId] = true
        end

        local clickRelative = LxDataHelper.ParseNumber_Sign(v.clickCancel, ',')
        if #clickRelative > 0 then
            self._clickRelativeMap[v.refId] = clickRelative
        end

    end
end

function ModelRedPoint:GetPara(key)
    return GameTable.HintPointBaseConfigRef[key]
end

