---resp
function ModelRedPoint:OnRedPointResp(pb)
    local synType = pb.syncType or 0
    if synType == 0 then
        if self._hasAdRP then
            self._redPointNetMap = self._redPointNetMap or {}
        else
            self._redPointNetMap = {}
        end
        self._hasAdRP = false
    end

    local actRedPointMap = self._actRedPointMap or {}

    for k, v in ipairs(pb.redPoint) do
        local refId = v.redPointRefId
        if (refId ~= 12101000) then
            ---@type StructRedPoint
            local redPoint = self._redPointNetMap[refId]
            if not redPoint then
                redPoint = StructRedPoint:New()
                self._redPointNetMap[refId] = redPoint
            end
            redPoint:CreateByPb(v)
            self:InsertCheckList(refId)

            if refId == 12400000 then
                gModelDungeonDaily:SetNetRedPointCache(redPoint)
            elseif refId == ModelRedPoint.PDT_NEW_REPORT_1 or
                    refId == ModelRedPoint.PDT_NEW_REPORT_2 then
                if redPoint.count > 0 and redPoint.clicked then
                    redPoint.clicked = false
                end
            end
        end

        local activityList = v.activityList
        if activityList then
            for j, k in ipairs(activityList) do
                local activityRed = StructActivityRedPoint:New()
                activityRed:CreateByPb(k)
                local sid = activityRed.sid
                if v.count == 0 then
                    actRedPointMap[sid] = nil
                else
                    actRedPointMap[sid] = activityRed
                end


            end
        end
    end

    self._actRedPointMap = actRedPointMap

    FireEvent(EventNames.ON_ACT_PAGE_RED_CHANGE, actRedPointMap)

    ---@type StructRedPoint
    local redPoint = self._redPointNetMap[ModelRedPoint.PDT_NEW_REPORT_1]
    FireEvent(EventNames.HIDE_PET_REPORT1, { showRP = redPoint and redPoint.count > 0 })

    redPoint = self._redPointNetMap[ModelRedPoint.PDT_NEW_REPORT_2]
    FireEvent(EventNames.HIDE_PET_REPORT2, { showRP = redPoint and redPoint.count > 0 })

    FireEvent(EventNames.ON_RED_CHANGE)
end

