function ModelRedPoint:GetChangeList(refId)
    local changeList = {}
    changeList[refId] = true

    local parentTypes = self._parentTypesList[refId]
    if parentTypes then
        for k, v in pairs(parentTypes) do
            changeList[v] = true
        end
    end

    for k1, v1 in pairs(self._onceRedTypRelative) do
        for k2, v2 in pairs(v1) do
            if changeList[k2] then
                changeList[k1] = true
                break
            end
        end
    end

    return changeList
end

