function ModelRedPoint:SetRedPointClicked(refId)


    local cfg = GameTable.HintPointConfigRef[refId]
    if not cfg then
        return
    end

    local adRedPointMap = self._adRedPointMap
    if not adRedPointMap then
        adRedPointMap = {}
        self._adRedPointMap = adRedPointMap
    end

    local disappear = cfg.disappearType
    if disappear == 2 or disappear == 3 then

        local data = self._redPointNetMap[refId]
        if not data then
            data = StructRedPoint:New()
            data:CreateByClient(refId, false)
            self._redPointNetMap[refId] = data
        end

        data:SetClicked()

        self:InsertCheckList(refId)

    elseif disappear == 5 then
        local data = self._redPointNetMap[refId]
        if data then
            data:SetClicked()

            self:InsertCheckList(refId)

        end
    end
end

function ModelRedPoint:CheckRankRedClicked(sid)
    local refId = nil
    for k, v in pairs(self._rankIdsRedTypes) do
        local data = self._redPointNetMap[k]
        if data then
            local idMap = data:GetActivityRedMap()
            if idMap[sid] then
                data:SetMultiRedClicked(sid)
                refId = k
                break
            end
        end
    end
    if not refId then
        return
    end

    self:InsertCheckList(refId)

    self:InsertCheckList(ModelRedPoint.RANK_MAPRANK)

end

function ModelRedPoint:SetActivityRedClicked(sid)

    local refId = nil
    for k, v in pairs(self._activityRedTypes) do
        local data = self._redPointNetMap[k]
        if data then
            local idMap = data.idMap
            local isThis = idMap[sid]
            if isThis then
                data:SetMultiRedClicked(sid)
                refId = k
                break
            end
        end
    end
    local _specialRedPointMaps = self._specialRedPointMap
    local _specialRedPointMap = _specialRedPointMaps[sid]

    if _specialRedPointMap and not _specialRedPointMap.isClick then
        local bARef = GameTable.InnerActivityFuncTypeRef[sid]
        local eModel = bARef.eModel
        for i, v in pairs(_specialRedPointMaps) do
            local ref = GameTable.InnerActivityFuncTypeRef[v.sid]
            if ref and ref.eModel == eModel then
                local specialRedPointMap = _specialRedPointMaps[v.sid]
                if specialRedPointMap then
                    refId = specialRedPointMap.refId
                    specialRedPointMap.isClick = true
                    self._specialRedPointMap[v.sid] = specialRedPointMap
                end
            end
        end
    end

    if not refId then
        return
    end

    self:InsertCheckList(refId)

end

function ModelRedPoint:CheckShowRedPoint(refId)
    --检查显示红点
    local showRed = self:CheckShowRedPointInternal(refId)
    return showRed
end

function ModelRedPoint:CheckShowRedPointInternal(refId)
    local isOpen = self:CheckFunctionOpen(refId)

    if not isOpen then
        return false
    end
    
    local isShowRed = self:CheckSingle(refId)
    if isShowRed then
        return true
    end

    local data = self._redPointNetMap[refId] --点击取消的红点，不在检查子红点
    if data and data.clicked then
        isShowRed =  false
    end

    local childTypes = self._childRedTypeList[refId]
    if childTypes then
        for k, v in pairs(childTypes) do
            local isFatherOpen = self:CheckFatherOpen(v)
            if isFatherOpen then
                isOpen = self:CheckFunctionOpen(v)
                if isOpen and self:CheckSingle(v) then
                    return true
                end
                if isOpen and self:CheckAdsRedPointShow(v) then
                    return true
                end
            end
        end
    end
    --
    if refId == 10000020 or refId == 10100000 or refId == 10100000 then
        -- 效外, 玩法
        if gModelFish:HadRed() then
            return true
        end

        if gModelDesireTrail:HadRed() then
            return true
        end
    end

    --这里如果还是false的花园则在进行判断
    if refId == 21000000 or refId == 21008100 or refId == 21008000 then
        local isOpen = gModelFunctionOpen:CheckIsOpened(21008100)
        if not isOpen then 
            return false
        end 
        
        if gModelQuest:IsHaveFinishTaskByType(182) then
            return true
        end
        if gModelMagicPot:GetGiftRedPoint() then
            return true
        end

        if gModelMagicPot:GetRewardRedpoint() then
            return true
        end
    end
    
    return isShowRed
end

function ModelRedPoint:CheckFatherOpen(refId)
    local fatherList = self._parentTypesList[refId]
    local isOpen = true
    for k, v in pairs(fatherList) do
        isOpen = self:CheckFunctionOpen(v)
        if not isOpen then
            return false
        end
    end

    return true
end

function ModelRedPoint:CheckFunctionOpen(redPointType)
    local funcId = self._redIdToFuncId[redPointType]
    if funcId then
        local isOpen = gModelFunctionOpen:CheckIsOpened(funcId)
        if not isOpen then
            return false
        end
    end
    return true
end

function ModelRedPoint:CheckSingle(redPointType)
    local data = self._redPointNetMap[redPointType]
    if data and data.clicked then
        return false
    end
    local checkFunc = self._checkShowRedFunc[redPointType]
    if checkFunc then
        local isShowRed = checkFunc()
        return isShowRed
    end
    if data then
        -- 这里如果为12400000
        if redPointType == 12400000 then
            local isRed_1 = self:Check_12400000_RedpoingState()
            local isRed_2 = data.count ~= 0
            return isRed_1 and isRed_2
        else
            if redPointType == 19101000 then
                printInfoN2("-------------------19101000", "---count--" .. data.count)
            end

            return data.count ~= 0
        end


    end
    return false
end

function ModelRedPoint:Check_12400000_RedpoingState()
    local typeList = gModelDungeonDaily:GetTypeConfig()
    local isRed = false
    for k, v in ipairs(typeList) do
        local isShow = false
        local isFreeGetRedpoint = gModelDungeonDaily:CheckShowDungeonRed_New_1(k)
        local isNewChallenge = gModelDungeonDaily:CheckShowDungeonRed_New_2(k)

        isShow = isFreeGetRedpoint

        if not isShow then
            isShow = isNewChallenge
        end

        isRed = isShow

        if isRed then
            break
        end
    end

    return isRed
end

