function ModelRedPoint:CheckSpecialActivityRedStatus(sid)
    if sid == 421 then
        printInfoN2("---", "--")
    end

    local showRed = false
    local actRef = gModelActivity:GetActivityFunsById(sid)
    if not actRef then
        return false
    end

    local isOpen = gModelFunctionOpen:CheckIsOpened(actRef.functionOpenRefId)
    if not isOpen then
        return false
    end

    local eModel = actRef.eModel
    if actRef.redPoint > 0 then
        --if eModel == ModelActivity.ATTENTION_WECHAT then
        --    local serverOpen = gLGameLogin:IsOpenFocusWeChat()
        --    if not serverOpen then
        --        return false
        --    end
        --end
        local isClick = self:GetSpecialRedPointMapIsClickBySid(sid)
        if isClick then
            return false
        else
            local showRed = self:CheckShowRedPoint(actRef.redPoint)
            return showRed
        end
    elseif eModel == ModelActivity.DREAM_SECRET then
        return gModelActivity:HasNewSecret()
    end
    return showRed
end

