function ModelRedPoint:CheckOncePointRed(refId)

    local data = self._redPointNetMap[refId]
    if data then
        return data.count ~= 0
    end

    local show = false
    local relatives = self._onceRedTypRelative[refId]
    if relatives then
        for k, v in pairs(relatives) do
            show = self:CheckShowRedPoint(k)
            if show then
                break
            end
        end
    end

    local onceCheckFun = self._onceCheckFun[refId]
    if onceCheckFun then
        show = onceCheckFun()
    end

    if show then
        self:SetOncePointRed(refId)
    end

    return show
end

