function ModelRedPoint:GetRedPointNetData(refId)
    local redPointData = self._redPointNetMap and self._redPointNetMap[refId]
    return redPointData
end

function ModelRedPoint:InsertCheckList(redPointId)

    if not self:NeedCheck(redPointId) then
        return
    end

    if not self._checkRefIdList then
        self._checkRefIdList = {}
        self._checkRefIdMap = {}
    end

    if not self._checkRefIdMap[redPointId] then
        table.insert(self._checkRefIdList, redPointId)
        self._checkRefIdMap[redPointId] = true
    end

end

function ModelRedPoint:CheckListUpdate()
    if not self._checkRefIdList then
        return
    end

    local cnt = 10
    local keylist = {}
    while true do
        local redPoint = table.remove(self._checkRefIdList, 1)
        if not redPoint then
            break
        end

        keylist[redPoint] = true

        cnt = cnt - 1
        if cnt <= 0 then
            break
        end

    end

    local allIds = {}
    for k, v in pairs(keylist) do
        self._checkRefIdMap[k] = nil
        local changeList = self:GetChangeList(k)
        for k1, v1 in pairs(changeList) do
            allIds[k1] = true
        end
    end

    for k, v in pairs(allIds) do
        self:RefreshRedPoint(k)
    end

end

function ModelRedPoint:StartCheckTimer()
    if not self._timer then
        return
    end

    self._timer:TimerRemoveByKey("checkRedPointList")
    self._timer:TimerCreate("checkRedPointList", function()
        self:CheckListUpdate()
    end, 0.2, false, -1)
end

