function ModelRedPoint:SetAdsShopRedPoint(refId,str)
    self._hasAdRP = true
    local redPointNetMap = self._redPointNetMap
    if not redPointNetMap then
        redPointNetMap = {}
        self._redPointNetMap = redPointNetMap
    end
    ---@type StructRedPoint
    local redPoint = redPointNetMap[refId]
    if not redPoint then
        redPoint = StructRedPoint:New()
        self._redPointNetMap[refId] = redPoint
    end
    redPoint:SetAdsShopData(refId,str)
    self:InsertCheckList(refId)
    return true
end


function ModelRedPoint:SetAdsRedPoint(refId)
    local ref = GameTable.HintPointConfigRef[refId]
    if not ref then return false end

    self._hasAdRP = true

    local adRedPointMap = self._adRedPointMap
    if not adRedPointMap then
        adRedPointMap = {}
        self._adRedPointMap = adRedPointMap
    end
    ---@type StructRedPoint
    local redPoint = adRedPointMap[refId]
    if not redPoint then
        redPoint = StructRedPoint:New()
        adRedPointMap[refId] = redPoint
    end
    redPoint:CreateByAds(refId,true)

    self:InsertCheckList(refId)
    return true
end

function ModelRedPoint:SetAdsRedPointClick(refId)
    local adRedPointMap = self._adRedPointMap
    if not adRedPointMap then
        adRedPointMap = {}
        self._adRedPointMap = adRedPointMap
    end
    if not adRedPointMap[refId] then return end
    ---@type StructRedPoint
    local redPoint = adRedPointMap[refId]
    redPoint:CreateByAds(refId,false)
    self:InsertCheckList(refId)
end

function ModelRedPoint:CheckAdsRedPointShow(refId)
    if not refId or refId < 1 then return false end

    if not self:CheckFunctionOpen(refId) then return false end

    local adRedPointMap = self._adRedPointMap
    local adRedPoint = adRedPointMap and adRedPointMap[refId]
    if adRedPoint and adRedPoint.adCount > 0 then
        return true
    end
    return false
end

