function ModelRedPoint:CheckActivityHasRed(sid)
    if self:CheckShowRedPoint(10405111) then
        return true
    end
    ---@type StructActivityRedPoint
    local actRPData = self:GetActRedPointMap(sid)
    if not actRPData then return false end

    local pageList = actRPData.pageList or {}
    for i,v in ipairs(pageList) do
        if v > 0 then
            return true
        end
    end

    for k,v in pairs(actRPData.entryList) do
        for pageId,entrysRP in pairs(v) do
            if entrysRP then
                return true
            end
        end
    end

    return false
end

return ModelRedPoint